'use strict';
let baseData, data;
const money=n=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(n);
const pct=(a,b)=>b?`${(100*a/b).toFixed(1)}%`:'N/A'; const div=(a,b)=>b?a/b:null; const show=n=>n===null?'N/A':money(n);
const unique=(arr,k)=>[...new Set(arr.map(x=>x[k]))].sort();
function filtered(){return data.leads.filter(l=>(!from.value||l.date>=from.value)&&(!to.value||l.date<=to.value)&&['source','campaign','service','geography','segment','owner'].every(k=>!document.getElementById(k).value||l[k]===document.getElementById(k).value));}
function render(){const leads=filtered(), q=leads.filter(x=>x.qualified), sched=leads.filter(x=>x.estimateScheduled), comp=leads.filter(x=>x.estimateCompleted), prop=leads.filter(x=>x.proposalSent), wins=leads.filter(x=>x.stage==='Won'), revenue=leads.reduce((a,x)=>a+x.revenue,0),gp=leads.reduce((a,x)=>a+x.grossProfit,0);const visibleSources=new Set(leads.map(x=>x.source)),cost=data.costs.filter(x=>visibleSources.has(x.source)).reduce((a,x)=>a+x.cost,0),responses=leads.map(x=>x.responseMinutes).sort((a,b)=>a-b),median=responses.length?responses[Math.floor(responses.length/2)]:null;
const cards=[['Marketing spend',money(cost)],['Total leads',leads.length],['Qualified leads',q.length],['Estimate requests',leads.filter(x=>x.estimateRequested).length],['Estimates scheduled',sched.length],['Estimates completed',comp.length],['Proposals sent',prop.length],['Jobs won',wins.length],['Revenue booked',money(revenue)],['Gross profit booked',money(gp)],['Cost per lead',show(div(cost,leads.length))],['Cost per qualified lead',show(div(cost,q.length))],['Cost per scheduled estimate',show(div(cost,sched.length))],['Customer-acquisition cost',show(div(cost,wins.length))],['ROAS',cost?(revenue/cost).toFixed(2)+'×':'N/A'],['Gross-profit ROAS',cost?(gp/cost).toFixed(2)+'×':'N/A'],['Close rate',pct(wins.length,prop.length)],['Average job value',show(div(revenue,wins.length))],['Average GP/job',show(div(gp,wins.length))],['Pipeline value','Not established'],['Weighted pipeline','Not established'],['Median response time',median===null?'N/A':median+' min'],['Missed-call rate','Unavailable'],['Referral contribution',pct(leads.filter(x=>x.referral).reduce((a,x)=>a+x.revenue,0),revenue)],['Repeat-account revenue',money(leads.filter(x=>x.repeat).reduce((a,x)=>a+x.revenue,0))]];
cardsEl.innerHTML=cards.map(x=>`<div class="card"><small>${x[0]}</small><strong>${x[1]}</strong><small>Synthetic</small></div>`).join(''); resultCount.textContent=`${leads.length} synthetic leads shown.`;
const stages=['New','Contacted','Qualified','Disqualified','Estimate Scheduled','Estimate Completed','Proposal Sent','Won','Lost','No Response','Future Opportunity'];const count=s=>s==='Qualified'?q.length:s==='Estimate Scheduled'?sched.length:s==='Estimate Completed'?comp.length:s==='Proposal Sent'?prop.length:leads.filter(x=>x.stage===s).length;funnel.innerHTML=stages.map(s=>`<div class="funnel-row"><span>${s}</span><span class="bar" style="width:${leads.length?Math.max(2,100*count(s)/leads.length):2}%"></span><strong>${count(s)}</strong></div>`).join('');
const sources=[...new Set(leads.map(x=>x.source))];sourcesBody.innerHTML=sources.map(s=>{const z=leads.filter(x=>x.source===s),zq=z.filter(x=>x.qualified),ze=z.filter(x=>x.estimateScheduled),zw=z.filter(x=>x.stage==='Won'),zr=z.reduce((a,x)=>a+x.revenue,0),zg=z.reduce((a,x)=>a+x.grossProfit,0),zc=data.costs.filter(x=>x.source===s).reduce((a,x)=>a+x.cost,0);return `<tr><td>${s}</td><td>${z.length}</td><td>${zq.length}</td><td>${ze.length}</td><td>${zw.length}</td><td>${money(zr)}</td><td>${money(zg)}</td><td>${money(zc)}</td><td>${show(div(zc,z.length))}</td><td>${show(div(zc,zq.length))}</td><td>${show(div(zc,zw.length))}</td><td>${show(div(zr,z.length))}</td><td>${show(div(zg,z.length))}</td><td>${pct(zw.length,zq.length)}</td></tr>`}).join('');
}
function staticViews(){campaignBody.innerHTML=data.campaigns.map(c=>{const l=data.leads.filter(x=>x.campaign===c.name),q=l.filter(x=>x.qualified).length,w=l.filter(x=>x.stage==='Won').length,r=l.reduce((a,x)=>a+x.revenue,0),g=l.reduce((a,x)=>a+x.grossProfit,0);return `<tr><td>${c.name}</td><td>${money(c.spend)}</td><td>${c.clicks}</td><td>${c.impressions}</td><td>${pct(c.clicks,c.impressions)}</td><td>${show(div(c.spend,c.clicks))}</td><td>${c.calls}</td><td>${c.forms}</td><td>${q}</td><td>${w}</td><td>${money(r)}</td><td>${money(g)}</td><td>${c.searchQuality}; ${c.availability}</td></tr>`}).join('');
channelCards.innerHTML=[['GBP calls',data.seo.gbpCalls],['GBP website clicks',data.seo.websiteClicks],['Reviews',data.seo.reviews],['Average rating',data.seo.averageRating],['Social content',data.social.contentPublished],['Social views',data.social.views],['Assisted leads',data.social.assistedLeads],['Qualified social leads',data.social.qualifiedLeads],['Revenue influenced',data.social.revenueInfluenced],['Production burden',data.social.burdenHours+' synthetic hours']].map(x=>`<div class="card"><small>${x[0]}</small><strong>${x[1]}</strong><small>Synthetic / validation required</small></div>`).join('');
b2Body.innerHTML=data.b2b.map(x=>`<tr><td>${x.account}</td><td>${x.tier}</td><td>${x.stage}</td><td>${x.opportunities}</td><td>${money(x.bidValue)}</td><td>${x.ageDays} synthetic days</td></tr>`).join('');alerts.innerHTML=data.alerts.map(x=>`<article class="alert"><strong>${x.type} · ${x.urgency}</strong><div>${x.entity}: ${x.action}</div></article>`).join('');expBody.innerHTML=data.experiments.map(x=>`<tr><td>${x.id}</td><td>${x.hypothesis}</td><td>${x.channel}</td><td>${x.audience}</td><td>${x.control}</td><td>${x.variation}</td><td>${x.start}–${x.end||'open'}</td><td>${x.primaryMetric}</td><td>${x.guardrail}</td><td>${x.sampleSize}</td><td>${x.result}</td><td>${x.decision}</td><td>${x.followUp}</td><td>${x.revenueImpact}</td><td>${x.confidence}</td><td>${x.status}</td></tr>`).join('');decisions.innerHTML=data.decisions.map(x=>`<article class="alert"><strong>${x.id} · ${x.status}</strong><div>${x.question}</div><small>${x.recommendation}</small></article>`).join('');}
function populate(){['source','campaign','service','geography','segment','owner'].forEach(k=>unique(data.leads,k).forEach(v=>document.getElementById(k).insertAdjacentHTML('beforeend',`<option>${v}</option>`)));}
const cardsEl=document.getElementById('cards'),resultCount=document.getElementById('result-count'),funnel=document.getElementById('funnel'),sourcesBody=document.getElementById('sources'),campaignBody=document.getElementById('campaigns'),channelCards=document.getElementById('channel-cards'),b2bBody=document.getElementById('b2b-table'),alerts=document.getElementById('alerts'),expBody=document.getElementById('experiment-table'),decisions=document.getElementById('decisions'),from=document.getElementById('from'),to=document.getElementById('to');
fetch('data/sample-data.json').then(r=>r.json()).then(d=>{baseData=d;data=structuredClone(d);populate();staticViews();render()}).catch(()=>document.body.insertAdjacentHTML('afterbegin','<p class="banner">Sample data failed to load. Run through the documented local HTTP server.</p>'));
document.querySelectorAll('.filters input,.filters select').forEach(x=>x.addEventListener('change',render));document.querySelectorAll('.tab').forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.view').forEach(v=>v.hidden=v.id!==b.dataset.view)}));
document.getElementById('reset').addEventListener('click',()=>{document.querySelectorAll('.filters input,.filters select').forEach(x=>x.value='');data=structuredClone(baseData);render()});document.getElementById('export').addEventListener('click',()=>{const rows=filtered(),keys=Object.keys(rows[0]||{}),csv=[keys.join(','),...rows.map(r=>keys.map(k=>JSON.stringify(r[k]??'')).join(','))].join('\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='synthetic-filtered-leads.csv';a.click();URL.revokeObjectURL(a.href)});
